# After tool use, send result back with text explanation
message = client.messages.create(
    model="claude-opus-4-8",
    max_tokens=1024,
    tools=[{"name": "get_weather", ...}],
    messages=[
        {"role": "user", "content": "What's the weather in SF?"},
        {"role": "assistant", "content": message.content},  # Tool use
        {
            "role": "user",
            "content": [
                {
                    "type": "text",
                    "text": "Here's the tool result:"
                },
                {
                    "type": "tool_result",
